{
  description = "Infernal NixOS - Imprecation & Impermanence. [github.com/lowcache/infernalnixos.git]";
  inputs = {
    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";
    home-manager = {
      url = "github:nix-community/home-manager";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    nixos-hardware.url = "github:NixOS/nixos-hardware/master";
    nix-cachyos-kernel.url = "github:xddxdd/nix-cachyos-kernel";
    impermanence.url = "github:nix-community/impermanence";
    lanzaboote = {
      url = "github:nix-community/lanzaboote";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    microvm = {
      url = "github:astro/microvm.nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    quickshell = {
      url ="git+https://git.outfoxxed.me/outfoxxed/quickshell";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    lix-module = {
      url = "git+https://git.lix.systems/lix-project/nixos-module";
      inputs.nixpkgs.follows = "nixpkgs";
      inputs.lix.url = "git+https://git.lix.systems/lix-project/lix";
    };
    sops-nix = {
      url = "github:Mic92/sops-nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    infernal-init = {
      url = "github:lowcache/infernal-init";
      inputs.nixpkgs.follows = "nixpkgs";
    };
  };

  outputs = { self, nixpkgs, home-manager, microvm, infernal-init, ... }@inputs: {
    nixosConfigurations.nondeus = nixpkgs.lib.nixosSystem {
      system = "x86_64-linux";
      specialArgs = { inherit inputs; };
      modules = [
      	{ nixpkgs.overlays = [ inputs.nix-cachyos-kernel.overlays.pinned ]; }
        ./nixos/configuration.nix
        ./nixos/hardware-configuration.nix
        inputs.lanzaboote.nixosModules.lanzaboote
        inputs.impermanence.nixosModules.impermanence
        inputs.lix-module.nixosModules.default
        inputs.sops-nix.nixosModules.sops
        home-manager.nixosModules.home-manager
        {
          home-manager.useGlobalPkgs = true;
          home-manager.useUserPackages = true;
          home-manager.extraSpecialArgs = { inherit inputs; };
          home-manager.users.nondeus = import ./home;
        }
      ];
    };

    # Add this to allow building/running the VM package
    packages.x86_64-linux.net-gate = self.nixosConfigurations.nondeus.config.microvm.vms.net-gate.config.microvm.declaredRunner;
  };
}

{ config, pkgs, inputs, lib, ... }: {

  imports = [
    ./vms.nix
  ];



  # Kernel & Performance
  boot = {
    initrd.systemd.enable = true;
    kernelModules = [ "nvidia_uvm" "amdgpu" ];
    kernelParams = [
      "nvidia.NVreg_EnableGpuFirmware=1"
      "nvidia_drm.modeset=1"
      "nvidia_drm.fbdev=1"
      "preempt=full"
      "threadirqs"
    ];
    kernelPackages = pkgs.cachyosKernels.linuxPackages-cachyos-latest;
    kernel.sysctl = {
      # Memory Management
      "vm.max_map_count" = 2147483642;
      "vm.swappiness" = 180;
      "vm.page-cluster" = 0;
      "vm.vfs_cache_pressure" = 50;
      # Scheduling
      "kernel.sched_cfs_bandwidth_slice_us" = 3000;
      # Network
      "net.core.netdev_max_backlog" = 16384;
      "net.core.somaxconn" = 8192;
      "net.ipv4.tcp_fastopen" = 3;
      "net.ipv4.tcp_slow_start_after_idle" = 0;
      "net.core.default_qdisc" = "fq";
      "net.ipv4.tcp_congestion_control" = "bbr";
    };
    loader = {
      systemd-boot = {
        enable = lib.mkForce false;
        configurationLimit = 10;
      };
      efi.canTouchEfiVariables = true;
    };
    lanzaboote = {
      enable = true;
      pkiBundle = "/etc/secureboot";
    };
  };

  networking = {
    networkmanager = {
      enable = true;
      wifi.scanRandMacAddress = true;
    };
  };

  systemd = {
    oomd.enable = false;
    tmpfiles.rules = [
      "d /home/nondeus 0700 nondeus users"
      "d /home/nondeus/AppImage 0755 nondeus users"
      "d /home/nondeus/Storage/ai-generation 0755 nondeus users"
      "d /home/nondeus/Storage/ai-generation/fooocus 0755 nondeus users"
      "d /home/nondeus/Storage/ai-generation/forge 0755 nondeus users"
    ];
    services = {
      greetd.serviceConfig = {
        StandardInput = "tty";
        StandardOutput = "tty";
        StandardError = "journal";
        TTYReset = true;
        TTYHangup = true;
        TTYDeallocate = true;
      };
      nix-daemon.serviceConfig.KillMode = "process";
      decapitate-fuse-mounts = {
        description = "Force lazy unmount of xdg-document-portal FUSE to release /nix";
        before = [ "local-fs.target" ];
        wantedBy = [ "shutdown.target" "reboot.target" "halt.target" ];
        serviceConfig = {
          Type = "oneshot";
          DefaultDependencies = false;
          ExecStart = "${pkgs.coreutils}/bin/umount -f -l /run/user/1000/doc || true";
          ExecStopPost = "${pkgs.psmisc}/bin/killall -9 xdg-document-portal fusermount3";
        };
      };
    };
    settings.Manager = {
      DefaultTimeoutStopSec = "10s";
      DefaultRestartSec = "1s";   
    };
    user.extraConfig = "DefaultTimeoutStopSec=5s";
  };

  users.users.root = {
    hashedPasswordFile = config.sops.secrets.root_password.path;
  };

  users.users.nondeus = {
    isNormalUser = true;
    hashedPasswordFile = config.sops.secrets.user_password.path;
    extraGroups = [ "adbusers" "networkmanager" "wheel" "video" "docker" ];
  };

  sops = {
    defaultSopsFile = ./secrets.yaml;
    defaultSopsFormat = "yaml";
    age.sshKeyPaths = [ "/persist/etc/ssh/ssh_host_ed25519_key" ];
    secrets = {
      user_password = {
        neededForUsers = true;
      };
      root_password = {
        neededForUsers = true;
      };
    };
  };
  programs = {
    hyprland = {
      enable = true;
      withUWSM = true;
    };
    appimage = {
      enable = true;
      binfmt = true;
    };
    kdeconnect.enable = true;
    fish.enable = true;
  };

  virtualisation.docker = {
    enable = true;
    autoPrune.enable = true;
    liveRestore = false;
  };

  virtualisation.oci-containers = {
    backend = "docker";
    containers = {
      "fooocus" = {
        image = "ghcr.io/lllyasviel/fooocus:latest";
        autoStart = false;
        ports = [ "7865:7865" ];
        volumes = [ "/home/nondeus/Storage/ai-generation/fooocus:/content/data" ];
        environment = {
          CMDARGS = "--listen";
          DATADIR = "/content/data";
          config_path = "/content/data/config.txt";
          path_checkpoints = "/content/data/models/checkpoints/";
          path_loras = "/content/data/models/loras/";
          path_outputs = "/content/data/outputs/";
        };
        extraOptions = [ "--device" "nvidia.com/gpu=0" ];
      };
      "forge" = {
        image = "ghcr.io/ai-dock/stable-diffusion-webui-forge:latest-cuda";
        autoStart = false;
        ports = [ "7866:17860" ];
        volumes = [ "/home/nondeus/Storage/ai-generation/forge:/workspace" ];
        environment = {
          # AI-Dock Specific Vars
          BASE_PORT = "17860";
          WORKSPACE = "/workspace";
          # WebUI Specific Vars
          FORGE_ARGS = "--listen --port 17860";
        };
        extraOptions = [ "--device" "nvidia.com/gpu=0" ];
      };
    };
  };

  # Application Support
  services = {
    timesyncd.enable = true;
    xserver.videoDrivers = [ "nvidia" "amdgpu" ];
    geoclue2.enable = true;
    scx = {
      enable = true;
      scheduler = "scx_lavd";
    };
    flatpak.enable = true;
    asusd.enable = true;
    supergfxd.enable = true;
    power-profiles-daemon.enable = true;
    logind.settings = {
      Login = {
        KillUserProcesses = true;
      };
    };
    greetd = {
      enable = true;
      settings = {
        default_session = {
          command = "${pkgs.tuigreet}/bin/tuigreet --time --cmd 'uwsm start hyprland.desktop'";
          user = "greeter";
        };
      };
    };
  };

  xdg.portal = {
    enable = true;
    extraPortals = [ pkgs.xdg-desktop-portal-gtk ];
  };

  environment.systemPackages = with pkgs; [
    sbctl
    cryptsetup
    wireguard-tools
    tor
    uwsm
    android-studio
    android-tools
    appimage-run
  ];

  nix = {
    settings = {
      experimental-features = [ "nix-command" "flakes" ];
      auto-optimise-store = true;
      substituters = [ "https://hyprland.cachix.org" "https://nix-community.cachix.org" ];
      trusted-public-keys = [ 
        "hyprland.cachix.org-1:a7pgxzMz7+chwVL3/pzj6jIBMioiJM7ypFP8PwtkuGc=" 
        "nix-community.cachix.org-1:mB9FSh9qf2dCimDSUo8Zy7bkq5CX+/rkCWyvRCYg3Fs=" 
      ];
      min-free = 536870912; # 512MB
      max-free = 1073741824; # 1GB
    };
    gc = {
      automatic = true;
      dates = "weekly";
      options = "--delete-older-than 7d";
    };
    optimise.automatic = true;
  };

  nixpkgs = {
    config = {
      allowUnfree = true;
      cudaSupport = true;
    };
  };

  system.stateVersion = "24.11";

  time.timeZone = "America/Chicago";
}

